// PARSE FIRST NAME
//
// Recebe name (nome completo) e devolve firstName.
// Trata nomes compostos, espacos extras e valores ausentes.

var senderName = $('Edit Fields4').last().json.data.lead.name;

if (senderName === null || senderName === undefined) {
