// ═══════════════════════════════════════════════════════════════════════
// CODE SPLIT OUT — quebra a resposta em bolhas curtas (estilo conversa humana)
// Alvo: 1–2 frases por mensagem; teto absoluto de 3 frases.
// Preserva como UMA mensagem: delivery_mode "atomic" (questionário trade-in),
// blocos estruturados (cadastro / questionário "R:") e simulações (proposta
// com preços/parcelas). Saída count-agnostic: formattedResponse.messages.
// Propaga transfer, repasse_message e link_built para os nós de envio.
// ═══════════════════════════════════════════════════════════════════════

var input = $input.first().json;

var alana      = input.alana || {};
var textoRaw   = alana.message || "";
var transfer   = alana.transfer || false;
var repasseMsg = alana.repasse_message || null;
var linkBuilt  = input.link_built || null;

var normalized = String(textoRaw)
  .replace(/\r?\n/g, "\n")
  .replace(/"/g, "'")
  .trim();

// Quebra em frases: pontuação final seguida de espaço e início de nova frase.
// Não quebra decimais (1.299) nem URLs (sem espaço após o ponto). Parágrafos
// (\n\n) são fronteiras fortes; \n simples vira espaço dentro do bloco.
function splitSentences(s) {
  var out = [];
  var blocks = s.split(/\n{2,}/);
  for (var b = 0; b < blocks.length; b++) {
    var block = blocks[b].replace(/\n/g, " ").trim();
    if (!block) continue;
    var re = /([.?!…])\s+(?=[A-ZÁÉÍÓÚÂÊÔÃÕÇ0-9"'(])/g;
    var last = 0, m;
    while ((m = re.exec(block)) !== null) {
      var cut = m.index + m[0].length;
      out.push(block.slice(last, cut).trim());
      last = cut;
    }
    if (last < block.length) out.push(block.slice(last).trim());
  }
  return out.filter(Boolean);
}

// Agrupa frases em bolhas: alvo 1–2 frases, teto 3, mescla fragmentos curtos
// (ex.: "Show!") para não enviar bolhas minúsculas demais.
function groupSentences(sents) {
  var SOFT_CHARS = 170;
  var msgs = [];
  var cur = "";
  var count = 0;
  for (var i = 0; i < sents.length; i++) {
    var sent = sents[i];
    if (cur === "") { cur = sent; count = 1; continue; }
    var merged = cur + " " + sent;
    var curIsTiny = cur.length < 45;
    var withinSoft = (count + 1) <= 2 && merged.length <= SOFT_CHARS;
    var canAttach = count < 3 && (curIsTiny || withinSoft);
    if (canAttach) { cur = merged; count += 1; }
    else { msgs.push(cur); cur = sent; count = 1; }
  }
  if (cur) msgs.push(cur);
  return msgs;
}

// Bloco estruturado (questionário trade-in "R:" / cadastro): não fragmentar —
// o cliente copia/edita como UMA mensagem no WhatsApp.
function isStructuredBlock(s) {
  var lines = String(s).split("\n");
  var rCount = 0, labelCount = 0;
  for (var i = 0; i < lines.length; i++) {
    var t = lines[i].trim();
    if (t === "R:") rCount++;
    if (t.length > 0 && t.length <= 40 && t.charAt(t.length - 1) === ":") labelCount++;
  }
  return rCount >= 2 || labelCount >= 3;
}

// Simulação / proposta de preço: preservar a mensagem inteira (à vista + parcelas).
function looksLikeSimulation(s) {
  var installments = (s.match(/\b\d{1,2}\s?x\b/gi) || []).length;
  var prices = (s.match(/R\$\s?\d/gi) || []).length;
  return installments >= 2 || prices >= 3;
}

var deliveryMode = input.delivery_mode || alana.delivery_mode || "normal";
var preserveWhole = deliveryMode === "atomic"
  || isStructuredBlock(normalized)
  || looksLikeSimulation(normalized);

var parts = preserveWhole ? [normalized] : groupSentences(splitSentences(normalized));
if (parts.length === 0) { parts = [normalized]; }

var messages = [];
for (var i = 0; i < parts.length; i++) {
  if (parts[i]) { messages.push({ key: "string" + (i + 1), text: parts[i] }); }
}

return [
  {
    json: {
      formattedResponse: {
        messages: messages,
        meta: {
          total:     messages.length,
          preserved: preserveWhole,
          hasSecond: Boolean(messages[1]),
          hasThird:  Boolean(messages[2])
        }
      },
      transfer:        transfer,
      repasse_message: repasseMsg,
      link_built:      linkBuilt
    }
  }
];

const inputData = $('Edit Fields5').last().json;
const crmResponse = $input.first().json ?? {};
// REPASSE SWITCH2 ROUTING FLAGS: o Code Routing Flags (após Edit Fields5)
// é o dono das flags transitórias; o spread de inputData não as traz.
const routingFlags = $('Code Routing Flags').last().json ?? {};

function parseMaybeJson(value) {
  if (value == null) return null;
  if (typeof value === "object") return value;
  if (typeof value !== "string") return null;
  try {
    return JSON.parse(value);
  } catch (error) {
    return null;
  }
}

function firstObject(candidates) {
  for (const candidate of candidates) {
    const parsed = parseMaybeJson(candidate);
    if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) return parsed;
  }
  return {};
}

function readLeadState(response) {
  const data = response?.data ?? {};
  const firstLead = Array.isArray(data?.leads) ? data.leads[0] : null;
  const firstConversation = Array.isArray(data?.conversations) ? data.conversations[0] : null;
  return firstObject([
    response?.lead_state,
    response?.leadState,
    response?.state,
    data?.lead_state,
    data?.leadState,
    data?.state,
    data?.lead?.lead_state,
    data?.lead?.state,
    firstLead?.lead_state,
    firstLead?.state,
    firstConversation?.lead_state,
    firstConversation?.state,
    firstConversation?.lead?.lead_state,
    firstConversation?.lead?.state,
  ]);
}

function pickFirstPresent(...values) {
  for (const value of values) {
    if (value !== null && value !== undefined && value !== "") return value;
  }
  return null;
}

const leadState = readLeadState(crmResponse);
const persistedInventory = leadState.last_inventory_context ?? leadState.memory?.last_inventory_context ?? null;
const refreshedStockItemId = pickFirstPresent(
  inputData.stock_item_id,
  inputData.memory?.stock_item_id,
  inputData.inventory?.stock_item_id,
  inputData.inventory?.best_item?.stock_item_id,
  leadState.stock_item_id,
  leadState.memory?.stock_item_id,
  leadState.last_inventory_context?.stock_item_id,
  leadState.last_inventory_context?.best_item?.stock_item_id,
  persistedInventory?.stock_item_id,
  persistedInventory?.best_item?.stock_item_id
);
const refreshedStockCity = pickFirstPresent(
  inputData.stock_city,
  inputData.memory?.stock_city,
  leadState.stock_city,
  leadState.memory?.stock_city,
  persistedInventory?.stock_city,
  persistedInventory?.best_item?.city
);
const refreshedCrossCity = pickFirstPresent(
  inputData.cross_city_situation,
  inputData.memory?.cross_city_situation,
  leadState.cross_city_situation,
  leadState.memory?.cross_city_situation,
  persistedInventory?.cross_city_situation
) ?? false;
const lastInventoryContext = inputData.last_inventory_context ?? inputData.memory?.last_inventory_context ?? persistedInventory ?? null;

const nextBestAction = inputData.next_best_action ?? inputData.memory?.next_best_action ?? leadState.next_best_action ?? leadState.memory?.next_best_action ?? null;
const simulationCount = Number(inputData.simulation_count ?? inputData.memory?.simulation_count ?? leadState.simulation_count ?? leadState.memory?.simulation_count ?? 0);
const wantsSimulation = [
  "simular orçamento",
  "simular orcamento",
  "re-simular com cor alternativa",
  "re-simular com PIX 250 como entrada",
].includes(nextBestAction);
const shouldSimulateNow = routingFlags.shouldSimulateNow === true || inputData.shouldSimulateNow === true || inputData.memory?.shouldSimulateNow === true || (
  !!refreshedStockItemId &&
  (routingFlags.context_ready === true || inputData.context_ready === true) &&
  !!inputData.card_brand &&
  inputData.simulation_done !== true &&
  simulationCount < 3 &&
  inputData.tradein_disqualified !== true &&
  inputData.tradein_model_accepted !== false &&
  wantsSimulation
);

return [{
  json: {
    ...inputData,
    lead_state: leadState,
    stock_item_id: refreshedStockItemId,
