    next_best_action: routingFlags.next_best_action ?? inputData.next_best_action ?? nextBestAction,
    memory: {
      ...(inputData.memory ?? {}),
      stock_item_id: refreshedStockItemId,
      stock_city: refreshedStockCity,
      cross_city_situation: refreshedCrossCity,
