// ---- pré-cálculos ----
const intent = state.intent ?? "";
const tradeinOk = tradeinEvaluationComplete(state);
const cashEntryOk = state.cash_entry_intent !== true || (state.cash_entry_amount !== null && state.cash_entry_amount !== undefined);
