// REPASSE V2 MULTI QUOTE READINESS
const repasseV2DesiredDevices = Array.isArray(state.desired_devices)
  ? state.desired_devices.filter(d => d && (d.desired_model || d.model) && (d.desired_capacity || d.capacity)).slice(0, 2)
  : [];
